// GraphQL response から products + variants を展開し BQ insert 用 row 配列に

const resp = $input.first().json;
const products = (resp && resp.data && resp.data.products) || {};
const edges = products.edges || [];
const hasNextPage = products.pageInfo && products.pageInfo.hasNextPage;

if (hasNextPage) {
  // 250+ products = 拡張が必要 (現状想定 < 100)
  console.log('WARN: hasNextPage=true, paging not implemented. Some products skipped.');
}

const now = new Date().toISOString();
const todayJST = new Date(Date.now() + 9*60*60*1000).toISOString().split('T')[0];
const rows = [];

for (const edge of edges) {
  const p = edge.node;
  const productId = p.id.replace('gid://shopify/Product/', '');
  for (const ve of ((p.variants && p.variants.edges) || [])) {
    const v = ve.node;
    rows.push({
      fetched_date: todayJST,
      product_id: productId,
      product_title: p.title,
      variant_id: v.id.replace('gid://shopify/ProductVariant/', ''),
      sku: v.sku || null,
      variant_title: v.title || null,
      price: v.price ? Math.round(parseFloat(v.price)) : null,
      cost_price: (v.inventoryItem && v.inventoryItem.unitCost && v.inventoryItem.unitCost.amount)
        ? Math.round(parseFloat(v.inventoryItem.unitCost.amount)) : null,
      inventory_item_id: v.inventoryItem ? v.inventoryItem.id.replace('gid://shopify/InventoryItem/', '') : null,
      currency: (v.inventoryItem && v.inventoryItem.unitCost && v.inventoryItem.unitCost.currencyCode) || 'JPY',
      inserted_at: now
    });
  }
}

return rows.map(json => ({ json }));
